const d = $input.first().json;
const AUTHORIZED = ['bridge.digital.solution@gmail.com','gelsonmascarenhas@gmail.com','gelson_m@hotmail.com'];
const IC  = "https://inspiring-cat-production.up.railway.app";
const TG  = "https://api.telegram.org/bot***REDACTED_TELEGRAM_BOT_TOKEN***";

let source = 'unknown', decision = null, action_id = null, sender = null, reply_to = null;

if (d.callback_query) {
  const cb = d.callback_query.data || '';
  const m = cb.match(/^COS:(A|R):(cos-[a-f0-9]{8})$/);
  if (m) { decision = m[1] === 'A' ? 'approve' : 'reject'; action_id = m[2]; }
  sender = String(d.callback_query.from.id);
  reply_to = { type: 'telegram_callback', query_id: d.callback_query.id, chat_id: String(d.callback_query.message.chat.id) };
  source = 'telegram_button';
  try {
    await fetch(TG + '/answerCallbackQuery', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ callback_query_id: d.callback_query.id, text: decision === 'approve' ? '✅ Processing...' : '❌ Processing...' }),
      signal: AbortSignal.timeout(5000)
    });
  } catch(e) {}
}
else if (d.message && d.message.text) {
  const text = d.message.text.trim();
  const m = text.match(/^(approve|yes|reject|no)\s+(cos-[a-f0-9]{8})/i);
  if (m) {
    decision  = (m[1].toLowerCase() === 'yes' || m[1].toLowerCase() === 'approve') ? 'approve' : 'reject';
    action_id = m[2].toLowerCase();
  }
  sender   = String(d.message.from.id);
  reply_to = { type: 'telegram_message', chat_id: String(d.message.chat.id) };
  source   = 'telegram_message';
  // Save chat_id to DB
  const cid = String(d.message.chat.id);
  const SAVE_PY = `import os,psycopg2
db=os.environ['DATABASE_URL'].replace('postgres://','postgresql://')
conn=psycopg2.connect(db);cur=conn.cursor()
cur.execute("CREATE TABLE IF NOT EXISTS cos_config(key TEXT PRIMARY KEY,value TEXT,updated_at TIMESTAMPTZ DEFAULT NOW())")
cur.execute("INSERT INTO cos_config(key,value)VALUES('telegram_chat_id','` + cid + `') ON CONFLICT(key)DO UPDATE SET value=EXCLUDED.value,updated_at=NOW()")
conn.commit();conn.close();print('SAVED_CHATID:` + cid + `')`;
  try {
    const sb64 = Buffer.from(SAVE_PY).toString('base64');
    const srep = await fetch(IC + '/tasks', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ type: 'shell', payload: { command: `python3 -c "import base64;exec(base64.b64decode('${sb64}').decode())"` } }),
      signal: AbortSignal.timeout(15000)
    });
    await srep.json();
  } catch(e) {}
}
else if (d.subject !== undefined || d.Subject !== undefined) {
  const subj = (d.subject || d.Subject || '').toLowerCase();
  const body = (d.text || d.bodyPreview || d.snippet || d.body || '').toLowerCase();
  const combined = subj + ' ' + body;
  const mId  = combined.match(/cos-([a-f0-9]{8})/i);
  const mDec = combined.match(/\b(approve|yes|reject|no)\b/i);
  if (mId) action_id = 'cos-' + mId[1].toLowerCase();
  if (mDec) { const w = mDec[1].toLowerCase(); decision = (w === 'approve' || w === 'yes') ? 'approve' : 'reject'; }
  sender   = (d.from || d.From || d.senderEmailAddress?.address || '').toLowerCase().replace(/.*<|>/g, '').trim();
  reply_to = { type: 'email', address: sender };
  source   = 'email';
}
else if (d.entry) {
  try {
    const msg = d.entry[0].changes[0].value.messages[0];
    const text = (msg.text?.body || '').trim();
    const m = text.match(/^(approve|yes|reject|no)\s+(cos-[a-f0-9]{8})/i);
    if (m) { decision = (m[1].toLowerCase() === 'yes' || m[1].toLowerCase() === 'approve') ? 'approve' : 'reject'; action_id = m[2].toLowerCase(); }
    sender   = msg.from;
    reply_to = { type: 'whatsapp', phone: msg.from };
    source   = 'whatsapp';
  } catch(e) {}
}

const authorized = AUTHORIZED.some(a => a === sender) || source === 'telegram_button' || source === 'telegram_message';

let action_valid = false, action_data = null;
if (action_id && decision) {
  const LOOKUP_PY = `import os,psycopg2,json
db=os.environ['DATABASE_URL'].replace('postgres://','postgresql://')
conn=psycopg2.connect(db);cur=conn.cursor()
cur.execute("SELECT id,service,severity,description,fix_cmd,status FROM cos_pending_actions WHERE id=%s",('` + action_id + `',))
row=cur.fetchone()
if row: print(json.dumps({'id':row[0],'service':row[1],'sev':row[2],'desc':row[3],'fix_cmd':row[4],'status':row[5]}))
else: print('NOT_FOUND')
conn.close()`;
  const lb64 = Buffer.from(LOOKUP_PY).toString('base64');
  const lrep = await fetch(IC + '/tasks', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ type: 'shell', payload: { command: `python3 -c "import base64;exec(base64.b64decode('${lb64}').decode())"` } }),
    signal: AbortSignal.timeout(20000)
  });
  const ltr = await lrep.json();
  for (let i = 0; i < 10; i++) {
    await new Promise(r => setTimeout(r, 2000));
    const s = await (await fetch(IC + '/tasks/' + ltr.id, { signal: AbortSignal.timeout(10000) })).json();
    if (s.status === 'done' || s.status === 'error') {
      const out = (s.output || '').trim();
      if (out && out !== 'NOT_FOUND') { try { action_data = JSON.parse(out); action_valid = action_data.status === 'pending'; } catch(e) {} }
      break;
    }
  }
}

const can_execute = authorized && action_valid && decision === 'approve';
return [{ json: { source, decision, action_id, sender, authorized, action_valid, can_execute, action_data, reply_to } }];

const { action_id, action_data, reply_to, sender, source } = $input.first().json;
