    if (s.status === 'done' || s.status === 'error') { fix_output = (s.output || '').slice(0, 500); fix_status = s.status; break; }
  }
} catch(e) { fix_output = 'Task failed: ' + e.message; }

const UPDATE_PY = `import os,psycopg2,json
db=os.environ['DATABASE_URL'].replace('postgres://','postgresql://')
conn=psycopg2.connect(db);cur=conn.cursor()
