});
const utr = await uResp.json();
for (let i = 0; i < 6; i++) {
  await new Promise(r => setTimeout(r, 2000));
  const s = await (await fetch(IC + '/tasks/' + utr.id, { signal: AbortSignal.timeout(10000) })).json();
  if (s.status === 'done' || s.status === 'error') break;
}

const resultMsg = fix_status === 'done'
  ? '✅ <b>Fix executed successfully</b>\n\n<code>' + action_data.service + '</code>\n<code>' + action_id + '</code>\n\nOutput:\n<pre>' + (fix_output || '(no output)').replace(/</g,'&lt;') + '</pre>'
