if (chat_id) {
  await fetch(TG + '/sendMessage', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id, text: resultMsg, parse_mode: 'HTML' }),
    signal: AbortSignal.timeout(10000)
  });
}

return [{ json: { executed: true, action_id, fix_status, fix_output } }];

