    txt = '⚠️ <b>Could not process request</b>\n\nAction ID not found or already handled. Check the ID and ensure it has not expired (24h window).';
  }
  try {
    await fetch(TG + '/sendMessage', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chat_id, text: txt, parse_mode: 'HTML' }),
      signal: AbortSignal.timeout(10000)
    });
  } catch(e) {}
}

return [{ json: { rejected: true, action_id, status: newStatus } }];
